from kafka import KafkaConsumer
import json

# Define the Kafka consumer configuration
consumer_config = {
    'bootstrap_servers': ['localhost:9092'],
    'group_id': 'financial_transactions_group',
    'auto_offset_reset': 'earliest',
    'enable_auto_commit': True,
    'key_deserializer': lambda x: x.decode('utf-8'),
    'value_deserializer': lambda x: json.loads(x.decode('utf-8'))
}

# Define the message handlers
def handle_deposit(event):
    print(f"Processing deposit event: {event}")

def handle_withdrawal(event):
    print(f"Processing withdrawal event: {event}")

def handle_transfer(event):
    print(f"Processing transfer event: {event}")

# Create a dictionary to map event types to their handlers
message_handlers = {
    'deposit': handle_deposit,
    'withdrawal': handle_withdrawal,
    'transfer': handle_transfer
}

# Create the Kafka consumer
consumer = KafkaConsumer('financial_transactions', **consumer_config)

# Consume messages and process them
for message in consumer:
    event_type = message.value['type']
    if event_type in message_handlers:
        handler = message_handlers[event_type]
        handler(message.value)
    else:
        print(f"Unknown event type: {event_type}")